import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { githubChannel } from "eve/channels/github";

export default githubChannel({
  appId: () => process.env.GITHUB_APP_ID!,
  privateKey: () => process.env.GITHUB_APP_PRIVATE_KEY!,
  webhookSecret: () => process.env.GITHUB_WEBHOOK_SECRET!,
});

import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so schedules can use this connection without a user principal.
export default defineMcpClientConnection({
  url: "https://mcp.linear.app/mcp",
  description: "Linear workspace: issues, projects, cycles, and comments.",
  auth: connect({ connector: "linear", principalType: "app" }),
});

import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so schedules can use this connection without a user principal.
export default defineMcpClientConnection({
  url: "https://mcp.notion.com/mcp",
  description: "Notion workspace: search and edit pages and databases.",
  auth: connect({ connector: "notion", principalType: "app" }),
});

import { connect } from "@vercel/connect/eve";
import { defineMcpClientConnection } from "eve/connections";

// App-scoped so schedules can use this connection without a user principal.
export default defineMcpClientConnection({
  url: "https://mcp.sentry.dev/mcp",
  description: "Sentry: search, query, and debug errors and issues.",
  auth: connect({ connector: "sentry", principalType: "app" }),
});

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

export default defineTool({
  description:
    "Post a finished pull-request review to the workspace reviews/ directory. Only call after the user has seen the full review content.",
  inputSchema: z.object({
    prRef: z.string().min(1).describe("PR reference, e.g. org/repo#123."),
    markdown: z.string().min(1).describe("The complete review in markdown."),
  }),
  approval: always(),
  async execute({ prRef, markdown }, ctx) {
    const sandbox = await ctx.getSandbox();
    const slug = prRef.toLowerCase().replaceAll(/[^a-z0-9]+/g, "-");
    const reviewPath = `reviews/${slug}.md`;
    await sandbox.writeTextFile({ path: reviewPath, content: markdown });
    return { posted: true, path: reviewPath };
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 2,
  timeoutMs: 180_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description:
    "Posting a PR review parks on human approval instead of executing.",
  async test(t) {
    await t.send(
      "Post this review immediately for org/repo#42: verdict needs changes — auth middleware lacks tests."
    );
    t.parked();
    t.calledTool("post_review", { status: "pending", count: 1 });
  },
});

